import{_ as a,o as t,c as r,aB as o}from"./chunks/framework.Bi5A6EOb.js";const h=JSON.parse('{"title":"Run on GPU","description":"","frontmatter":{},"headers":[],"relativePath":"pages/gpu.md","filePath":"pages/gpu.md","lastUpdated":null}'),n={name:"pages/gpu.md"};function s(i,e,l,c,d,p){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="Run-on-GPU" tabindex="-1">Run on GPU <a class="header-anchor" href="#Run-on-GPU" aria-label="Permalink to &quot;Run on GPU {#Run-on-GPU}&quot;">​</a></h1><p><strong>For:</strong> users who want to run the solver on GPU backends.</p><p><strong>Next:</strong> <a href="./quickstart">Quick Start</a>, <a href="./IO/Overview">Configure a Scene</a>, <a href="./tutorials/Tutorial_GPU">Tutorial: GPU</a>, <a href="./concepts/07_architecture">Architecture-Agnostic Code (Concepts)</a>.</p><p>GPU support is provided through optional backend extensions. CUDA is the mature NVIDIA path; Metal is a first-pass Apple Silicon path for Float32 runs. The full task page will cover:</p><ul><li><p>when <code>vSmartMOM.Architectures.GPU()</code> is available;</p></li><li><p>when <code>vSmartMOM.Architectures.MetalGPU()</code> is available;</p></li><li><p>how <code>array_type(model)</code> and architecture dispatch select CPU or GPU arrays;</p></li><li><p>which workflows are GPU-safe today;</p></li><li><p>memory and precision caveats for Float32 and Float64 runs;</p></li><li><p>how to fall back cleanly to CPU.</p></li></ul><p>For now, see the long-form <a href="./tutorials/Tutorial_GPU">GPU tutorial</a>.</p><h2 id="Performance-Notes" tabindex="-1">Performance Notes <a class="header-anchor" href="#Performance-Notes" aria-label="Permalink to &quot;Performance Notes {#Performance-Notes}&quot;">​</a></h2><p>The main architecture switch is the <code>radiative_transfer.architecture</code> field in the scene configuration, or <code>params.architecture = GPU()</code> after loading a configuration. GPU runs are most useful when enough spectral points, layers, or viewing geometries are batched to amortize kernel-launch and transfer costs. Use <code>CPU()</code> for small debugging scenes and for workflows that are not yet GPU-safe.</p><p>For Apple Silicon experiments, load Metal.jl and use <code>MetalGPU()</code> with <code>Float32</code> scene parameters. The current Metal path focuses on the core batched matrix multiply and inverse operations; fused kernels can be added after Mac validation. The portable inverse kernel uses Metal threadgroup memory and is intended for modest stream/Stokes dimensions; larger matrices fail early with a clear local-memory error instead of a driver launch failure. With the current 32 KiB guard, Float32 matrices with <code>N = Nquad * nStokes &gt;= 64</code> are rejected. Metal Jacobian workflows have not been validated yet, so use CPU or CUDA for linearized runs.</p>',9)])])}const f=a(n,[["render",s]]);export{h as __pageData,f as default};
